import java.io.*;
public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            int marks = Integer.parseInt(br.readLine().trim());
            char grade;
            if (marks > 90) grade = 'A';
            else if (marks > 70) grade = 'B';
            else if (marks >= 40) grade = 'C';
            else grade = 'F';
            sb.append(grade);
            if (i + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def grade(marks):
    if marks > 90:
        return 'A'
    elif marks > 70:
        return 'B'
    elif marks >= 40:
        return 'C'
    else:
        return 'F'

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
T = int(data[0])
out = []
idx = 1
for _ in range(T):
    marks = int(data[idx])
    idx += 1
    out.append(grade(marks))
print('\n'.join(out))

